// Enhanced Message display function with queue system
const messageQueue = [];
let isMessageShowing = false;

function showMessageBox(message, color = '#ff4444', duration = 3500) {
    messageQueue.push({ message, color, duration });
    if (!isMessageShowing) {
        displayNextMessage();
    }
}

function displayNextMessage() {
    if (messageQueue.length === 0) {
        isMessageShowing = false;
        return;
    }

    isMessageShowing = true;
    const { message, color, duration } = messageQueue.shift();
    const box = document.getElementById("customMessageBox");
    
    box.textContent = message;
    box.style.background = color;
    box.style.display = "block";
    box.style.opacity = '1';
    
    setTimeout(() => {
        box.style.transition = "opacity 0.5s";
        box.style.opacity = '0';
        setTimeout(() => {
            box.style.display = "none";
            box.style.transition = '';
            setTimeout(displayNextMessage, 300); // Small delay between messages
        }, 500);
    }, duration);
}

// Enhanced Word counter for textareas
function updateCounter(textareaId, counterId, minWords = 0) {
    const textarea = document.getElementById(textareaId);
    const counter = document.getElementById(counterId);
    
    if (!textarea || !counter) return;
    
    const updateCount = () => {
        const text = textarea.value.trim();
        const wordCount = text === '' ? 0 : text.split(/\s+/).length;
        counter.textContent = wordCount;
        
        // Add warning if below minimum
        if (minWords > 0) {
            counter.style.color = wordCount < minWords ? '#ff4444' : '';
            counter.style.fontWeight = wordCount < minWords ? 'bold' : '';
        }
    };
    
    textarea.addEventListener('input', updateCount);
    updateCount(); // Initial count
}

// Initialize counters with minimum word requirements
document.addEventListener('DOMContentLoaded', () => {
    updateCounter("second-essay", "second-essay-counter", 200);
    updateCounter('third-essay', "third-essay-counter", 150);
});

// Enable all form fields before submission
function enableAllFormFields() {
    document.querySelectorAll('#applicationForm input, #applicationForm select, #applicationForm textarea').forEach(el => {
        el.disabled = false;
    });
}

async function submitForm(isFinal) {
    try {
        const form = document.getElementById("applicationForm");
        const formData = new FormData(form);

        // Add necessary fields
        formData.append('final_submission', isFinal ? '1' : '0');
        formData.append('is_ajax', '1');

       // In your submitForm function:
const response = await fetch('submit_application.php', {
    method: 'POST', // Still recommend POST for submissions
    body: formData,
    headers: {
        'X-Requested-With': 'XMLHttpRequest'
    },
    credentials: 'include'
});

        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }

        const result = await response.json();
        
        if (result.redirect) {
            // Handle final submission with form POST
            if (isFinal) {
                await handleFinalSubmission(formData);
                return;
            }
            window.location.href = result.redirect;
            return;
        }

        showMessageBox(result.message || (isFinal 
            ? "Application submitted successfully!" 
            : "Progress saved successfully!"), 
            "#098d0d");

    } catch (error) {
        console.error('Submission error:', error);
        showMessageBox(error.message || "An error occurred", "#ff4444");
    }
}

async function handleFinalSubmission(formData) {
    // Create a form dynamically for the final submission
    const form = document.createElement('form');
    form.method = 'POST';
    form.action = 'submit_application.php';
    form.style.display = 'none';
    
    // Add all form data to the new form
    for (let [key, value] of formData.entries()) {
        const input = document.createElement('input');
        input.type = 'hidden';
        input.name = key;
        input.value = value;
        form.appendChild(input);
    }
    
    document.body.appendChild(form);
    form.submit();
}

function setupButtonHandlers() {
    document.querySelectorAll('.save-btn, .submit-btn').forEach(button => {
        button.addEventListener('click', async function(e) {
            e.preventDefault();
            const isFinal = this.classList.contains('submit-btn');
            
            try {
                if (isFinal && !validateForm()) {
                    return;
                }

                await submitForm(isFinal);
                
            } catch (error) {
                showMessageBox(error.message || "An error occurred", "#ff4444");
            }
        });
    });

    // Enhanced submission confirmation
    document.querySelector(".submit-btn")?.addEventListener('click', async function(e) {
        e.preventDefault();
        
        if (!validateForm()) return;
        
        try {
            const confirmed = await showConfirmBox(
                "Are you sure you want to submit? You cannot edit after submission.",
                "#a31313"
            );
            
            if (confirmed) {
                // Show loading state
                const btn = this;
                const originalText = btn.textContent;
                btn.disabled = true;
                btn.textContent = "Submitting...";
                
                try {
                    await submitForm(true);
                } finally {
                    btn.disabled = false;
                    btn.textContent = originalText;
                }
            }
        } catch (error) {
            console.error('Submission error:', error);
            showMessageBox(error.message || "Submission failed", "#ff4444");
        }
    });

    // Save progress button with loading state
    document.querySelector(".save-btn")?.addEventListener("click", async function(e) {
        e.preventDefault();
        const btn = this;
        const originalText = btn.textContent;
        
        try {
            btn.disabled = true;
            btn.textContent = "Saving...";
            
            await submitForm(false);
            
        } catch (error) {
            console.error('Save error:', error);
            showMessageBox(error.message || "Error saving progress", "#ff4444");
        } finally {
            btn.disabled = false;
            btn.textContent = originalText;
        }
    });
}

// Enhanced Form validation
function validateForm() {
    const form = document.getElementById('applicationForm');
    let isValid = true;
    const errors = [];
    const warnings = [];

    // Required fields validation
    const requiredFields = [
        'full_name', 'email-address', 'contact-number', 
        'country', 'gender', 'birth-date', 'institution',
        'grade-year', 'gpa', 'interest', 'grade-previous',
        'first-essay', 'second-essay', 'third-essay', 
        'fourth-essay', 'hours_commitment', 'time_blocks'
    ];

    requiredFields.forEach(fieldName => {
        const field = form.querySelector(`[name="${fieldName}"]`);
        if (!field) return;
        
        if (field.type === 'radio' || field.type === 'checkbox') {
            const group = form.querySelectorAll(`[name="${fieldName}"]`);
            if (!Array.from(group).some(f => f.checked)) {
                errors.push(`Please select ${fieldName.replace('-', ' ')}`);
                isValid = false;
            }
        } else if (!field.value.trim()) {
            errors.push(`Please fill out ${fieldName.replace('-', ' ')}`);
            isValid = false;
        }
    });

    // Essay word count validation
    const essayRequirements = [
        { id: "second-essay", min: 200, name: "Second essay" },
        { id: "third-essay", min: 150, name: "Third essay" }
    ];

    essayRequirements.forEach(req => {
        const textarea = document.getElementById(req.id);
        if (textarea) {
            const wordCount = textarea.value.trim() === '' ? 0 : textarea.value.trim().split(/\s+/).length;
            if (wordCount < req.min) {
                warnings.push(`${req.name} must be at least ${req.min} words (current: ${wordCount})`);
                isValid = false;
            }
        }
    });

    // Display errors and warnings
    if (errors.length > 0 || warnings.length > 0) {
        const allMessages = [...errors, ...warnings].join('\n');
        showMessageBox(allMessages, "#ff4444", 5000);
    }

    return isValid;
}

// Multi-page form navigation with improved state management
const pages = Array.from(document.querySelectorAll(".form-page"));
let currentPage = 0;

function showPage(idx) {
    pages.forEach((page, i) => {
        page.style.display = i === idx ? "block" : "none";
    });
    
    document.querySelector(".prev-btn").style.display = idx === 0 ? "none" : "block";
    document.querySelector(".next-btn").style.display = idx === pages.length - 1 ? "none" : "block";
    document.querySelector('.submit-btn').style.display = idx === pages.length - 1 ? "block" : "none";
    
    // Save current page to localStorage
    localStorage.setItem("applicationCurrentPage", idx);
    
    // Scroll to top of form
    window.scrollTo({ top: 0, behavior: 'smooth' });
}

// Navigation buttons with auto-save
function setupNavigation() {
    document.querySelector('.next-btn')?.addEventListener("click", async function() {
        if (currentPage < pages.length - 1) {
            currentPage++;
            showPage(currentPage);
            try {
                await submitForm(false);
            } catch (err) {
                console.error('Auto-save error:', err);
            }
        }
    });

    document.querySelector('.prev-btn')?.addEventListener('click', async function() {
        if (currentPage > 0) {
            currentPage--;
            showPage(currentPage);
            try {
                await submitForm(false);
            } catch (err) {
                console.error('Auto-save error:', err);
            }
        }
    });
}

// Initialize page from localStorage
function initializePage() {
    const savedPage = parseInt(localStorage.getItem("applicationCurrentPage"), 10) || 0;
    currentPage = Math.min(savedPage, pages.length - 1);
    showPage(currentPage);
}

// Enhanced security: Input sanitization
const forbiddenPatterns = [
    /<script.*?>.*?<\/script>/gi, // Script tags
    /['"`]/, /(--|\#|\/\*)/, /(;|\|)/, // SQL injection patterns
    /(union|select|insert|update|delete|drop|alter|create|exec)/i // SQL keywords
];

function sanitizeInput(value) {
    let sanitized = value;
    forbiddenPatterns.forEach(pattern => {
        if (pattern.test(sanitized)) {
            sanitized = sanitized.replace(pattern, '');
            showSecurityAlert();
        }
    });
    return sanitized;
}

function showSecurityAlert() {
    const alertDiv = document.createElement("div");
    alertDiv.style.position = "fixed";
    alertDiv.style.top = "20px";
    alertDiv.style.left = "50%";
    alertDiv.style.transform = "translateX(-50%)";
    alertDiv.style.padding = "15px";
    alertDiv.style.backgroundColor = "#ff4444";
    alertDiv.style.color = "white";
    alertDiv.style.borderRadius = '5px';
    alertDiv.style.zIndex = "10000";
    alertDiv.style.boxShadow = "0 2px 10px rgba(0,0,0,0.2)";
    alertDiv.textContent = "Special characters or patterns that could be used for SQL injection are not allowed.";
    document.body.appendChild(alertDiv);
    setTimeout(() => {
        alertDiv.style.transition = "opacity 0.5s";
        alertDiv.style.opacity = '0';
        setTimeout(() => document.body.removeChild(alertDiv), 500);
    }, 3000);
}

// Apply input sanitization to all relevant fields
function setupInputSanitization() {
    const inputTypes = ["text", "tel", "number", "search", "url", "email"];
    
    inputTypes.forEach(type => {
        document.querySelectorAll(`input[type="${type}"]`).forEach(input => {
            input.addEventListener("input", function() {
                const pos = this.selectionStart;
                const oldValue = this.value;
                this.value = sanitizeInput(oldValue);
                if (this.value !== oldValue) {
                    this.setSelectionRange(pos - 1, pos - 1);
                }
            });
        });
    });
    
    document.querySelectorAll("textarea").forEach(textarea => {
        textarea.addEventListener('input', function() {
            const pos = this.selectionStart;
            const oldValue = this.value;
            this.value = sanitizeInput(oldValue);
            if (this.value !== oldValue) {
                this.setSelectionRange(pos - 1, pos - 1);
            }
        });
    });
}

// Enhanced Confirmation dialog
function showConfirmBox(message, color = '#a31313') {
    return new Promise(resolve => {
        const existing = document.getElementById("customConfirmBox");
        if (existing) existing.remove();
        
        const box = document.createElement("div");
        box.id = "customConfirmBox";
        box.style.position = 'fixed';
        box.style.top = '30px';
        box.style.left = "50%";
        box.style.transform = 'translateX(-50%)';
        box.style.padding = "18px 28px";
        box.style.background = color;
        box.style.color = "#fff";
        box.style.borderRadius = "7px";
        box.style.zIndex = '10001';
        box.style.boxShadow = "0 2px 10px rgba(0,0,0,0.2)";
        box.style.fontSize = '18px';
        box.style.minWidth = "320px";
        box.style.textAlign = "center";
        box.innerHTML = `
            <div style="margin-bottom:18px;">${message}</div>
            <button id="confirmYesBtn" style="margin-right:18px;padding:8px 18px;background:#388e3c;color:#fff;border:none;border-radius:4px;cursor:pointer;">Yes</button>
            <button id="confirmNoBtn" style="padding:8px 18px;background:#d32f2f;color:#fff;border:none;border-radius:4px;cursor:pointer;">No</button>
        `;
        
        document.body.appendChild(box);
        
        document.getElementById("confirmYesBtn").onclick = () => {
            box.remove();
            resolve(true);
        };
        
        document.getElementById('confirmNoBtn').onclick = () => {
            box.remove();
            resolve(false);
        };
    });
}

// Interest selection with ratings - enhanced version
function setupInterestSelection() {
    const customSelect = document.getElementById('custom-interest-select');
    if (!customSelect) return;

    const selectBtn = customSelect.querySelector('.select-btn');
    const listItems = customSelect.querySelector('.list-items');
    const btnText = selectBtn.querySelector('.btn-text');
    const hiddenInput = document.getElementById('interest-hidden');
    let selectedItems = [];

    // Initialize from saved data
    const items = customSelect.querySelectorAll('.item');
    items.forEach(item => {
        if (item.classList.contains('checked')) {
            selectedItems.push(item.getAttribute('data-value'));
        }
    });

    updateSelection();

    // Toggle dropdown
    selectBtn.addEventListener('click', () => {
        listItems.classList.toggle('open');
        selectBtn.classList.toggle('open');
    });

    // Item selection
    items.forEach(item => {
        item.addEventListener('click', function(e) {
            e.stopPropagation();
            item.classList.toggle('checked');
            selectedItems = Array.from(customSelect.querySelectorAll('.item.checked'))
                .map(el => el.getAttribute('data-value'));
            updateSelection();
        });
    });

    // Close when clicking outside
    document.addEventListener('click', e => {
        if (!customSelect.contains(e.target)) {
            listItems.classList.remove('open');
            selectBtn.classList.remove('open');
        }
    });

    function updateSelection() {
        // Update button text
        btnText.textContent = selectedItems.length > 0 
            ? `${selectedItems.length} Selected` 
            : 'Select Fields';
        
        // Update hidden input
        hiddenInput.value = selectedItems.join(',');
        
        // Render ratings
        renderInterestRatings(selectedItems);
    }
}

// Enhanced Interest ratings functionality
function renderInterestRatings(interests) {
    const container = document.getElementById('interest-ratings');
    if (!container) return;

    container.innerHTML = interests.map(interest => {
        const safeId = interest.replace(/[^a-zA-Z0-9]/g, '_');
        const ratingValue = (window.savedRatings && window.savedRatings[interest]) || 5;
        
        return `
            <div class="interest-rating-group">
                <label>
                    ${interest} self-rating: 
                    <span id="label-${safeId}">${ratingValue}</span>/10
                </label>
                <div class="slider-container">
                    <input type="range" min="0" max="10" step="1"
                        name="interest_ratings[${interest}]"
                        id="slider-${safeId}"
                        value="${ratingValue}"
                        oninput="updateSliderValue(this)">
                </div>
            </div>
        `;
    }).join('');

    // Style sliders
    interests.forEach(interest => {
        const safeId = interest.replace(/[^a-zA-Z0-9]/g, '_');
        const slider = document.getElementById(`slider-${safeId}`);
        if (slider) {
            updateSliderStyle(slider);
            slider.addEventListener('input', () => updateSliderStyle(slider));
        }
    });
}

function updateSliderValue(slider) {
    const labelId = 'label-' + slider.id.replace('slider-', '');
    const label = document.getElementById(labelId);
    if (label) {
        label.textContent = slider.value;
        updateSliderStyle(slider);
    }
}

function updateSliderStyle(slider) {
    const percentage = (slider.value / slider.max) * 100;
    slider.style.background = `linear-gradient(to right, #a31313 ${percentage}%, #d5d5d5 ${percentage}%)`;
}

// Initialize everything when DOM is loaded
document.addEventListener("DOMContentLoaded", function() {
    initializePage();
    setupButtonHandlers();
    setupNavigation();
    setupInputSanitization();
    setupInterestSelection();
    
    // Initialize counters
    updateCounter("second-essay", "second-essay-counter", 200);
    updateCounter('third-essay', "third-essay-counter", 150);
});

// Make functions available globally for inline event handlers
window.updateSliderValue = updateSliderValue;
window.updateSliderStyle = updateSliderStyle;